CREATE INDEX shapes_by_shape_id ON "public".shapes (shape_id);
CREATE INDEX ON "public".shapes (shape_id, shape_pt_sequence);

CREATE OR REPLACE VIEW "public".shapes_aggregated AS
SELECT
	shape_id,
	array_agg(shape_dist_traveled) AS distances_travelled,
	-- todo [breaking]: make this a geography!
	ST_MakeLine(array_agg(shape_pt_loc)) AS shape
FROM (
	SELECT
		shape_id,
		shape_dist_traveled,
		ST_AsText(shape_pt_loc)::geometry AS shape_pt_loc
	FROM "public".shapes
	ORDER by shape_id, shape_pt_sequence
) shapes
GROUP BY shape_id;


