-- todo: change this to be a table, add extended -> basic mapping
CREATE TYPE "public".route_type_val AS ENUM (
	-- basic types
	'0' -- 0 Ă”Ă‡Ă´ Tram, Streetcar, Light rail. Any light rail or street level system within a metropolitan area.
	, '1' -- 1 Ă”Ă‡Ă´ Subway, Metro. Any underground rail system within a metropolitan area.
	, '2' -- 2 Ă”Ă‡Ă´ Rail. Used for intercity or long-distance travel.
	, '3' -- 3 Ă”Ă‡Ă´ Bus. Used for short- and long-distance bus routes.
	, '4' -- 4 Ă”Ă‡Ă´ Ferry. Used for short- and long-distance boat service.
	, '5' -- 5 Ă”Ă‡Ă´ Cable tram. Used for street-level rail cars where the cable runs beneath the vehicle, e.g., cable car in San Francisco.
	, '6' -- 6 Ă”Ă‡Ă´ Aerial lift, suspended cable car (e.g., gondola lift, aerial tramway). Cable transport where cabins, cars, gondolas or open chairs are suspended by means of one or more cables.
	, '7' -- 7 Ă”Ă‡Ă´ Funicular. Any rail system designed for steep inclines.
	, '11' -- 11 Ă”Ă‡Ă´ Trolleybus. Electric buses that draw power from overhead wires using poles.
	, '12' -- 12 Ă”Ă‡Ă´ Monorail. Railway in which the track consists of a single rail or a beam.

	-- extended types
, '100' -- Railway Service
, '101' -- High Speed Rail Service
, '102' -- Long Distance Trains
, '103' -- Inter Regional Rail Service
, '104' -- Car Transport Rail Service
, '105' -- Sleeper Rail Service
, '106' -- Regional Rail Service
, '107' -- Tourist Railway Service
, '108' -- Rail Shuttle (Within Complex)
, '109' -- Suburban Railway
, '110' -- Replacement Rail Service
, '111' -- Special Rail Service
, '112' -- Lorry Transport Rail Service
, '113' -- All Rail Services
, '114' -- Cross-Country Rail Service
, '115' -- Vehicle Transport Rail Service
, '116' -- Rack and Pinion Railway
, '117' -- Additional Rail Service
, '200' -- Coach Service
, '201' -- International Coach Service
, '202' -- National Coach Service
, '203' -- Shuttle Coach Service
, '204' -- Regional Coach Service
, '205' -- Special Coach Service
