CREATE TYPE "public".wheelchair_accessibility AS ENUM (
	'unknown' -- 0 or empty - No accessibility information for the trip.
	, 'accessible' -- 1 Ă”Ă‡Ă´â”¬ĂˇVehicle being used on this particular trip can accommodate at least one rider in a wheelchair.
	, 'not_accessible' -- 2 Ă”Ă‡Ă´ No riders in wheelchairs can be accommodated on this trip.
);
CREATE CAST ("public".wheelchair_accessibility AS text) WITH INOUT AS IMPLICIT;

CREATE TYPE "public".bikes_allowance AS ENUM (
	'unknown' -- 0 or empty - No bike information for the trip.
	, 'allowed' -- 1 Ă”Ă‡Ă´ Vehicle being used on this particular trip can accommodate at least one bicycle.
	, 'not_allowed' -- 2 Ă”Ă‡Ă´ No bicycles are allowed on this trip.
);
CREATE CAST ("public".bikes_allowance AS text) WITH INOUT AS IMPLICIT;

