ALTER TABLE "public".stops
ADD CONSTRAINT stops_parent_station_fkey
FOREIGN KEY (parent_station) REFERENCES "public".stops;

CREATE INDEX ON "public".stops (parent_station);


;
-- pathways
-----------------

CREATE TYPE "public".pathway_mode_v AS ENUM (
	'walkway' -- 1
	, 'stairs' -- 2
	, 'moving_sidewalk_travelator' -- 3 Ă”Ă‡Ă´ moving sidewalk/travelator
	, 'escalator' -- 4
	, 'elevator' -- 5
	, 'fare_gate' -- 6 Ă”Ă‡Ă´ (or payment gate): A pathway that crosses into an area of the station where a proof of payment is required (usually via a physical payment gate).
	-- Fare gates may either separate paid areas of the station from unpaid ones, or separate different payment areas within the same station from each other. This information can be used to avoid routing passengers through stations using shortcuts that would require passengers to make unnecessary payments, like directing a passenger to walk through a subway platform to reach a busway.
	, 'exit_gate' -- 7 Ă”Ă‡Ă´ Indicates a pathway exiting an area where proof-of-payment is required into an area where proof-of-payment is no longer required.
);
CREATE CAST ("public".pathway_mode_v AS text) WITH INOUT AS IMPLICIT;

CREATE TABLE "public".pathways (
	pathway_id TEXT PRIMARY KEY,
	from_stop_id TEXT NOT NULL,
	FOREIGN KEY (from_stop_id) REFERENCES "public".stops (stop_id),
	to_stop_id TEXT NOT NULL,
	FOREIGN KEY (to_stop_id) REFERENCES "public".stops (stop_id),
	pathway_mode "public".pathway_mode_v NOT NULL,
	is_bidirectional BOOLEAN NOT NULL,
	length DOUBLE PRECISION, -- todo: add non-negative constraint
	traversal_time INTEGER, -- todo: add positive constraint
	stair_count INTEGER, -- todo: add non-0 constraint
	max_slope DOUBLE PRECISION,
	min_width DOUBLE PRECISION, -- todo: add positive constraint
	signposted_as TEXT,
	reversed_signposted_as TEXT
);

COPY "public".pathways (
	pathway_id,
	from_stop_id,
	to_stop_id,
	pathway_mode,
	is_bidirectional,
	length,
	traversal_time,
	stair_count,
	max_slope,
	min_width,
	signposted_as,
	reversed_signposted_as
) FROM STDIN csv;
\.


;
-- stop_times
-----------------

CREATE TYPE "public".pickup_drop_off_type AS ENUM (
	'regular' -- 0 or empty - Regularly scheduled pickup/dropoff.
	, 'not_available' -- 1 Ă”Ă‡Ă´ No pickup/dropoff available.
	, 'call' -- 2 Ă”Ă‡Ă´ Must phone agency to arrange pickup/dropoff.
	, 'driver' -- 3 Ă”Ă‡Ă´ Must coordinate with driver to arrange pickup/dropoff.
);
CREATE CAST ("public".pickup_drop_off_type AS text) WITH INOUT AS IMPLICIT;

CREATE TYPE "public".timepoint_v AS ENUM (
	'approximate' -- 0 Ă”Ă‡Ă´ Times are considered approximate.
	, 'exact' -- 1 or empty - Times are considered exact.
);
CREATE CAST ("public".timepoint_v AS text) WITH INOUT AS IMPLICIT;

CREATE TABLE "public".stop_times (
	trip_id TEXT NOT NULL,
	FOREIGN KEY (trip_id) REFERENCES "public".trips,
	-- https://gist.github.com/derhuerst/574edc94981a21ef0ce90713f1cff7f6
	arrival_time INTERVAL,
	departure_time INTERVAL,
	stop_id TEXT NOT NULL,
	FOREIGN KEY (stop_id) REFERENCES "public".stops,
	stop_sequence INT NOT NULL,
	stop_sequence_consec INT,
	stop_headsign TEXT,
	pickup_type "public".pickup_drop_off_type,
	drop_off_type "public".pickup_drop_off_type,
	shape_dist_traveled REAL,
	timepoint "public".timepoint_v,
	-- Used to implement frequencies.txt. Filled after COPY-ing, see below.
	trip_start_time INTERVAL
);

COPY "public".stop_times (
	trip_id,
	arrival_time,
	departure_time,
	stop_id,
	stop_sequence,
	stop_headsign,
	pickup_type,
	drop_off_type,
	shape_dist_traveled,
	timepoint
) FROM STDIN csv;
