-- transfers
-----------------

CREATE TYPE "public".transfer_type_v AS ENUM (
	'recommended' -- 0 or empty - Recommended transfer point between routes.
	, 'timed' -- 1 - Timed transfer point between two routes. The departing vehicle is expected to wait for the arriving one and leave sufficient time for a rider to transfer between routes.
	, 'minimum_time' -- 2 Ă”Ă‡Ă´ Transfer requires a minimum amount of time between arrival and departure to ensure a connection. The time required to transfer is specified by min_transfer_time.
	, 'impossible' -- 3 - Transfers are not possible between routes at the location.
	, 'in_seat' -- 4 - Passengers can transfer from one trip to another by staying onboard the same vehicle (an "in-seat transfer").
	, 're_board' -- 5 - In-seat transfers are not allowed between sequential trips. The passenger must alight from the vehicle and re-board.
);
CREATE CAST ("public".transfer_type_v AS text) WITH INOUT AS IMPLICIT;

CREATE TABLE "public".transfers (
	id SERIAL PRIMARY KEY,
	from_stop_id TEXT,
	FOREIGN KEY (from_stop_id) REFERENCES "public".stops,
	to_stop_id TEXT,
	FOREIGN KEY (to_stop_id) REFERENCES "public".stops,
	transfer_type "public".transfer_type_v,
	min_transfer_time INT,
	from_route_id TEXT,
	FOREIGN KEY (from_route_id) REFERENCES "public".routes,
	to_route_id TEXT,
	FOREIGN KEY (from_route_id) REFERENCES "public".routes,
	from_trip_id TEXT,
	FOREIGN KEY (from_trip_id) REFERENCES "public".trips,
	to_trip_id TEXT,
	FOREIGN KEY (from_trip_id) REFERENCES "public".trips
);

